/**
 * Auto-generated code below aims at helping you parse
 * the standard input according to the problem statement.
 **/

 type Cell = '_' | '0' | '1'
 type Field = [Cell, Cell][][]
 type Token = 'P' | 'R' | 'C'

 const size: number = parseInt(readline());
 const tower: Token[] = readline().split('').map(s => s as Token);

 const map: Field = []
 let x = 0
 let y = 0
 let v: 0 | 1 = 0
 for (let i = 0; i < 16; i++) {
     const ROW: string[] = readline().split('');
     for (let j = 0; j < 16; j++) {
         if (!map[j]) {
             map[j] = []
         }
         map[j][i] = [ROW[j * 2] as Cell, ROW[j * 2 + 1] as Cell]
         if (ROW[j*2] == '1') {
            x = j
            y = i
            v = 0
         } else if (ROW[j * 2 + 1] == '1') {
            x = j
            y = i
            v = 1
         }
     }
 }
 type Position = {
    x: number,
    y: number,
    v: 0 | 1,
 }
 const takenFields: Position[] = [{x, y, v}]
 type WorkUnit = {
     position: Position,
     tower: Token[] 
 }
 const queue: WorkUnit[] = []

 const solveForToken = (position: Position, token: Token): Position[] => {
     const result: Position[] = []
     const {x, y, v} = position
     switch (token) {
         case 'P': {
             if (v === 0) {
                 result.push(
                    {x, y, v: 1},
                    {x: x-1, y, v: 1},
                    {x, y: y - 1, v: 1}
                ) 
             } else {
                result.push(
                    {x, y, v: 0},
                    {x: x+1, y, v: 0},
                    {x, y: y + 1, v: 0}
                ) 
             }
             break
         }
         case 'R': {
             if (v === 0) {
                 result.push(
                     {x: x - 1, y: y - 1, v: 1},
                     {x: x - 1, y: y + 1, v: 1},
                     {x: x + 1, y: y - 1, v: 1}
                 )
             } else {
                result.push(
                    {x: x + 1, y: y + 1, v: 0},
                    {x: x - 1, y: y + 1, v: 0},
                    {x: x + 1, y: y - 1, v: 0}
                )
            }
             break
         }
         case 'C': {
            result.push(
                {x: x - 1, y, v},
                {x: x + 1, y, v},
                {x, y: y - 1, v},
                {x, y: y + 1, v},
                {x: x - 1, y: y + 1, v},
                {x: x + 1, y: y - 1, v},
            )
            break
         }
     }
    return result.filter(({x, y}) => x >= 0 && x <= 16 && y >= 0 && y <= 16)
 }


queue.push({
    position: {x, y, v},
    tower,
})
 const hashes = new Set<string>()
 let count = 0
 while (queue.length) {
     const unit = queue.pop()
    //  console.error(`Position: ${unit.position.x},${unit.position.y},${unit.position.v}; Tower is ${unit.tower.join('')}`)
    //  console.error(`Queue size: ${queue.length}`)
    count++
     if (unit && unit.tower.length) {
        const {position, tower} = unit
        const hash = `${position.x},${position.y},${position.v}:${tower.join('')}`
        if (hashes.has(hash)) {
            continue
        }
        hashes.add(hash)
        for (let tokenId in tower) {
            const token = tower[tokenId]
            const takenPositions = solveForToken(position, token)
            const remainingTower = tower.filter((_token, index) => index !== parseInt(tokenId))
            takenPositions.forEach(position => {
                if (tower.length > 1 && !hashes.has(`${position.x},${position.y},${position.v}:${remainingTower.join('')}`)) {
                    // console.error(`Adding queue item: ${position.x},${position.y},${position.v}; Tower is ${tower.filter((_token, index) => index !== parseInt(tokenId))}`)
                    queue.push({
                        position,
                        tower: remainingTower
                    })
                }
                takenFields.push(position)
            })
         }            
     }
 }

console.error(`Made ${count} calculations`)
 for (let y = 0; y < 16; y++) {
     let row = ''
     for (let x = 0; x < 16; x++) {
         for (let v = 0; v <= 1; v++) {
            let cell = map[x][y][v]
            if (cell !== '_' && takenFields.some(pos => pos.x == x && pos.y == y && pos.v == v)) {
                cell = '1'
            }
            row += cell
         }
     }
     console.log(row)
 }
